def search_posts():
    query = request.args.get('query')

    title_regex = re.compile(f'.*{query}.*', re.IGNORECASE | re.VERBOSE)
    body_regex = re.compile(f'.*{query}.*', re.IGNORECASE | re.VERBOSE)

